const body = $json.body ?? $json;

if (body.event === 'meta_embedded_signup_diagnostic' || body.diagnostic === true) {
  return [{ json: { ok: true, diagnostic: true, reached_n8n: true, received_at: new Date().toISOString() } }];
}

const connected = body.connected_account ?? {};
const signup = body.signup ?? {};
const owner = connected.owner ?? {
  client: body.client,
  user_id: body.user_id,
  team_id: body.team_id,
  account_id: body.account_id,
};

const code = body.code ?? signup.code;
const wabaId = body.waba_id ?? connected.waba_id;
const phoneNumberId = body.phone_number_id ?? connected.phone_number_id;
const businessId = body.business_id ?? connected.business_id;
const businessToken = body.business_token ?? connected.business_token;
const connectedAt = connected.connected_at ?? body.connected_at ?? new Date().toISOString();

const missing = [];
if (!code) missing.push('code');
if (!wabaId) missing.push('waba_id');
if (!phoneNumberId) missing.push('phone_number_id');
if (missing.length) {
  throw new Error('Missing required payload fields: ' + missing.join(', '));
}

const tokenMetadata = connected.token_metadata ?? body.token_metadata ?? {};
const staticData = $getWorkflowStaticData('global');
staticData.connectedWhatsappAccounts ??= {};
const key = wabaId + ':' + phoneNumberId;

staticData.connectedWhatsappAccounts[key] = {
  waba_id: wabaId,
  phone_number_id: phoneNumberId,
  business_id: businessId,
  business_token: businessToken,
  token_metadata: tokenMetadata,
  owner,
  state: body.state ?? signup.state,
  session: signup.session,
  status: connected.status ?? body.status ?? 'connected',
  connected_at: connectedAt,
  updated_at: new Date().toISOString(),
};

return [{
  json: {
    ok: true,
    stored: true,
    waba_id: wabaId,
    phone_number_id: phoneNumberId,
    business_id: businessId,
    status: staticData.connectedWhatsappAccounts[key].status,
    connected_at: connectedAt,
    token_received: Boolean(businessToken),
  },
}];
